class Solution:
    def maximumProduct(self, nums, m):
        n = len(nums)
        best = None
        cur_max = None
        cur_min = None
        for j in range(m - 1, n):
            left = j - m + 1
            v = nums[left]
            if cur_max is None or v > cur_max:
                cur_max = v
            if cur_min is None or v < cur_min:
                cur_min = v
            cand = max(nums[j] * cur_max, nums[j] * cur_min)
            if best is None or cand > best:
                best = cand
        return best

