var maximumProduct = function(nums, m) {
    const n = nums.length;
    let best = null, curMax = null, curMin = null;
    for (let j = m - 1; j < n; j++) {
        const left = j - m + 1;
        const v = nums[left];
        if (curMax === null || v > curMax) curMax = v;
        if (curMin === null || v < curMin) curMin = v;
        const cand = Math.max(nums[j] * curMax, nums[j] * curMin);
        if (best === null || cand > best) best = cand;
    }
    return best;
};
